<?php
namespace App\Domain\Combat;
use App\Domain\Combat\Data\CombatAction;use App\Domain\Combat\Data\CombatantStats;use App\Domain\Combat\Data\CombatResult;use App\Domain\Combat\Data\CombatRound;use App\Domain\Combat\Random\RandomNumberGenerator;
final class CombatSimulator {const MAX_ROUNDS=100;private $rng;public function __construct(RandomNumberGenerator $rng){$this->rng=$rng;}public function simulate(CombatantStats $character,CombatantStats $monster){$ch=$character->currentHealth();$mh=$monster->currentHealth();$initial=$this->initial($character,$monster,$ch,$mh);if($initial)return$initial;$rounds=[];for($n=1;$n<=self::MAX_ROUNDS;$n++){$actions=[];$characterFirst=$character->attackSpeed()>=$monster->attackSpeed();if($characterFirst){$actions[]=$this->attack($n,$character,$monster,$mh);$mh=end($actions)->defenderHealthAfter();if($mh>0){$actions[]=$this->attack($n,$monster,$character,$ch);$ch=end($actions)->defenderHealthAfter();}}else{$actions[]=$this->attack($n,$monster,$character,$ch);$ch=end($actions)->defenderHealthAfter();if($ch>0){$actions[]=$this->attack($n,$character,$monster,$mh);$mh=end($actions)->defenderHealthAfter();}}$rounds[]=new CombatRound($n,$actions);if($ch<=0||$mh<=0)break;}if($mh<=0){$status=CombatResultStatus::CHARACTER_VICTORY;$winner=$character->identifier();}elseif($ch<=0){$status=CombatResultStatus::MONSTER_VICTORY;$winner=$monster->identifier();}else{$status=CombatResultStatus::DRAW;$winner=null;}return new CombatResult($status,$winner,count($rounds),$character->currentHealth(),$ch,$monster->currentHealth(),$mh,$rounds);}
private function initial($c,$m,$ch,$mh){if($ch>0&&$mh>0)return null;if($ch===0&&$mh===0){$s=CombatResultStatus::DRAW;$w=null;}elseif($ch===0){$s=CombatResultStatus::MONSTER_VICTORY;$w=$m->identifier();}else{$s=CombatResultStatus::CHARACTER_VICTORY;$w=$c->identifier();}return new CombatResult($s,$w,0,$ch,$ch,$mh,$mh,[]);}private function attack($round,$a,$d,$health){$chance=max(5,min(95,75+$a->accuracyRate()-$d->evasionRate()));$chanceBp=(int)round($chance*100);$roll=$this->rng->integer(1,10000);$hit=$roll<=$chanceBp;$criticalChance=max(0,min(100,$a->criticalChance()));$criticalRoll=null;$critical=false;$damage=0;if($hit){$criticalRoll=$this->rng->integer(1,10000);$critical=$criticalRoll<=(int)round($criticalChance*100);$unrounded=$a->attack()*(1-$d->damageReductionRate()/100)*($critical?$a->criticalDamageMultiplier():1);$damage=max(1,(int)round($unrounded));}$after=max(0,$health-$damage);return new CombatAction($round,$a->identifier(),$d->identifier(),round($chance,2),$roll/100,$hit,round($criticalChance,2),$criticalRoll===null?null:$criticalRoll/100,$critical,$damage,$health,$after);}}
